#include <iostream>

using namespace std;

struct TreeNode
{
    int data;
    TreeNode *left;
    TreeNode *right;
};

void postorder(TreeNode *node)
{
    if (node == nullptr) return; // BASE CASE

    postorder(node->left);        // LEFT
    postorder(node->right);       // RIGHT
    cout << node->data << " ";    // NODE
}

int main()
{
    TreeNode *root = new TreeNode{1, nullptr, nullptr};
    root->left = new TreeNode{2, nullptr, nullptr};
    root->right = new TreeNode{3, nullptr, nullptr};
    root->left->left = new TreeNode{4, nullptr, nullptr};
    root->left->right = new TreeNode{5, nullptr, nullptr};

    postorder(root);

    return 0;
}

void deleteTree(TreeNode *node)
{
    if (node == nullptr) return;

    deleteTree(node->left);   // delete children FIRST
    deleteTree(node->right);
    delete node;               // THEN delete this node
}

